// Zip parallel arrays into one item per listing
const j = $input.first().json;
const n = (j.title || []).length;
const out = [];
for (let i = 0; i < n; i++) {
  out.push({ json: { title: j.title[i], price: j.price?.[i], url: j.url?.[i] } });
}
return out;

// Build a stable idempotency key per asset (djb2 hash, no deps)
function hash(s) {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16);
}
return $input.all().map(item => {
  const j = item.json;
  return { json: { ...j, idempotencyKey: hash([j.symbol, j.price].join('|')) } };
});
